INSERT INTO it_remedies (category, issue_type, symptoms, remedy_steps, action_text) VALUES 
('Billing', 'Duplicate Transactions', 'Two or more identical charges', 'Confirm transaction IDs are unique. If both are Posted, billing department must process manual reversal.', 'We have identified the duplicate transaction. Please allow 3-5 business days for the reversal to reflect on your statement.'),
('Billing', 'Tier Mismatch', 'Paying for Pro but only has Basic', 'Trigger manual sync of entitlement database. User must log out and back in to refresh token.', 'A sync has been triggered. Please log out and back in to refresh your session.'),
('Billing', 'Failed Auto-Renewal', 'Subscription lapsed despite valid payment method', 'Validate tokenized card status, retry capture in billing gateway, and reconcile webhook events for the renewal window.', 'We retried your renewal and reconciled your billing status. Please check your account again in 10-15 minutes.'),
('Billing', 'Invoice Not Generated', 'Payment posted but monthly invoice missing', 'Rebuild invoice job for the affected billing cycle and verify invoice sequence in finance queue.', 'Your invoice is being regenerated and will be available in the billing portal shortly.'),
('Access', 'MFA Lockout', 'Lost access to authenticator app or changed phone', 'Verify identity via security questions. Admin must Revoke Existing Tokens in Management Console.', 'Your MFA has been reset. Upon your next login, you will be prompted to set up a new method.'),
('Access', 'Integration Failure', 'Data not syncing with Jira, Slack, or SQL', 'Check API Heartbeat. If green, user likely has expired OAuth token.', 'Please navigate to Settings > Integrations and click Re-authorize for the affected service.'),
('Access', 'Password Reset Loop', 'Reset link works but login still fails repeatedly', 'Invalidate all active reset tokens, clear stale auth sessions, and issue a fresh one-time reset URL.', 'We have cleared stale login sessions and sent a new secure reset link to your email.'),
('Access', 'SSO Assertion Error', 'SAML login fails with audience or issuer mismatch', 'Compare IdP metadata with SP configuration, correct entity ID and ACS URL, then retest signed assertion.', 'Your SSO configuration has been corrected. Please try signing in through your identity provider again.'),
('Connectivity', 'VPN Disconnection', 'Cannot access internal servers remotely', 'Ensure use of GlobalProtect-Region-A gateway. Flush DNS cache using ipconfig /flushdns.', 'Please ensure you are on the GlobalProtect-Region-A gateway and run the flushdns command provided.'),
('Connectivity', 'Intermittent Packet Loss', 'Calls lag, SSH drops, and frequent timeout errors', 'Run continuous ping and traceroute, identify high-loss hop, and shift user to stable edge node.', 'We detected packet instability and moved your route to a healthier network path. Please reconnect and test.'),
('Connectivity', 'DNS Resolution Failure', 'Hostnames fail while direct IP access still works', 'Switch to managed DNS profile, clear resolver cache, and validate split-horizon records.', 'Your DNS settings were refreshed. Please retry access using the service hostname.'),
('Hardware', 'Peripheral Malfunction', 'Keyboard, Mouse, or Webcam not recognized', 'Perform hard power cycle (30s hold for laptops). If it fails, initiate physical replacement.', 'Please perform a hard power cycle. If the device is still not recognized, a replacement is required.'),
('Hardware', 'Overheating Laptop', 'Fan noise high, sudden throttling, or thermal shutdowns', 'Run hardware diagnostics, clear vents, update firmware fan curve, and replace thermal module if thresholds exceed policy.', 'We applied thermal troubleshooting steps. If overheating persists, we will arrange a hardware replacement.'),
('Hardware', 'Disk SMART Warning', 'System reports imminent drive failure or bad sectors', 'Back up user data immediately, run SMART extended test, and schedule SSD replacement with reimage.', 'Your data has been protected and a disk replacement workflow has been initiated.'),
('Security', 'Phishing/Spam', 'Suspicious link or attachment', 'Do not open link. Forward to soc@connectsphere.com and delete from inbox.', 'Do not open the link. Please forward the email to our SOC team and delete it.'),
('Security', 'Compromised Account Suspected', 'Unexpected login alerts, sent emails, or privilege changes', 'Force password reset, revoke all refresh/access tokens, review login IP history, and trigger SOC containment playbook.', 'We secured your account and revoked active sessions. Please reset your password and review recent activity.'),
('Security', 'Malware Detection', 'Endpoint alert triggered by antivirus or EDR policy', 'Isolate device from network, run full EDR scan, quarantine artifacts, and collect forensic logs.', 'Your device has been isolated for protection while we complete malware remediation.'),
('Performance', 'Application Slowness', 'Pages load slowly during normal business hours', 'Check service latency dashboards, identify bottlenecked API endpoints, and scale impacted worker pool.', 'We are tuning performance on impacted services. Please monitor response times over the next 30 minutes.'),
('Performance', 'Database Timeout', 'Queries exceed timeout threshold and return errors', 'Inspect slow query log, add missing index, and increase pool timeout only after query optimization.', 'We identified and optimized slow database operations. Please rerun your workflow.'),
('Email', 'Mailbox Quota Exceeded', 'Cannot send or receive due to full mailbox', 'Archive old items, purge recoverable items folder, and apply retention policy cleanup.', 'Mailbox space has been reclaimed. Email delivery should resume within a few minutes.'),
('Email', 'Delayed Delivery', 'Messages arrive 10-60 minutes late internally', 'Check mail transport queue health, resolve connector throttling, and replay deferred messages.', 'Mail flow delays were corrected and queued emails are being delivered now.'),
('Collaboration', 'Calendar Sync Conflict', 'Meetings duplicate or vanish across devices', 'Reset calendar cache, resync primary mailbox, and resolve duplicate organizer records.', 'Calendar synchronization has been repaired. Please refresh your calendar clients.'),
('Collaboration', 'Screen Share Failure', 'Cannot share screen in Teams/Zoom meeting', 'Verify app permissions, update GPU drivers, disable conflicting overlays, and restart conferencing client.', 'Screen sharing settings were corrected. Please rejoin the meeting and try again.'),
('Software', 'License Activation Error', 'Installed app opens in trial mode despite valid license', 'Revalidate license assignment in admin portal, clear local activation cache, and reactivate product.', 'Your license was revalidated and activation has been restored.'),
('Software', 'Update Rollback Required', 'Latest patch causes crashes after startup', 'Pin to previous stable release, capture crash dump, and block problematic version in deployment ring.', 'We rolled your software back to a stable version while engineering investigates the patch.'),
('Data', 'Report Data Mismatch', 'Dashboard totals differ from exported CSV records', 'Compare ETL run timestamps, validate transformation logic, and rebuild affected report cube.', 'Data consistency checks are running and the report dataset is being corrected.'),
('Data', 'Accidental Record Deletion', 'Important records removed unintentionally', 'Restore from point-in-time backup, validate integrity checksum, and audit user action trail.', 'We have initiated recovery from backup and will confirm once records are fully restored.'),
('Mobile', 'MDM Enrollment Failure', 'Corporate policy cannot be applied to mobile device', 'Remove stale enrollment profile, regenerate enrollment token, and re-enroll via company portal.', 'A fresh enrollment token has been issued. Please enroll the device again from the company portal.'),
('Mobile', 'Push Notification Missing', 'Critical alerts not received on iOS/Android', 'Verify notification channel permissions, refresh push token, and test delivery from notification service.', 'Push notification delivery has been reconfigured. Please test by triggering a new alert.'),
('Printing', 'Secure Print Not Releasing', 'User authenticates at printer but jobs remain held', 'Resync print server policy, verify badge mapping, and clear stuck spooler job ownership.', 'Secure print queue issues were corrected. Please resubmit the print job.'),
('Backup & Recovery', 'Backup Job Failure', 'Nightly backup failed for one or more endpoints', 'Check backup agent status, storage quota, and rerun incremental backup with error logging enabled.', 'Backup jobs are being rerun and monitored. We will confirm completion once verified.'),
('Compliance', 'DLP Policy Block', 'Legitimate file transfer blocked by data loss policy', 'Review DLP match reason, apply approved exception if policy criteria are met, and log compliance justification.', 'Your transfer request is under compliance review for a policy-safe exception.'),
('Network', 'Wi-Fi Authentication Failure', 'Cannot join corporate SSID with valid credentials', 'Reissue device certificate, forget SSID profile, and reconnect using updated EAP settings.', 'Wi-Fi authentication settings have been refreshed. Please reconnect to the corporate network.'),
('Cloud', 'Storage Access Denied', 'User sees permission denied in shared cloud folder', 'Validate IAM role inheritance, repair broken group mapping, and force ACL propagation.', 'Access permissions were repaired. Please refresh the folder and try again.'),
('Cloud', 'API Rate Limit Exceeded', 'Automation jobs fail with too many requests errors', 'Throttle client retries using exponential backoff and request temporary quota uplift for integration account.', 'We adjusted API retry behavior and are coordinating quota increase for stable automation runs.');